"use client";

import * as React from "react";
import {
  IconLuggage,
  IconMapPin,
  IconRoute,
} from "@tabler/icons-react";
import {
  Alert,
  AlertDescription,
  AlertTitle,
  Badge,
  MetadataList,
  RouteStops,
  type RouteStopItem,
} from "@gunjo/ui";

import {
  STAGE_DETAIL,
  STAGE_LABEL,
  isClaimable,
  isDelayed,
  type Bag,
  type BaggageRecord,
} from "./data";

/** 旅客向けの状態ラベル（RouteStops の汎用ラベルを手荷物文脈に上書き）。 */
const STATUS_LABELS = {
  completed: "完了",
  current: "現在",
  pending: "これから",
  delayed: "遅延",
  failed: "未着",
} as const;

/** Bag のステージ列を RouteStops の RouteStopItem[] に変換する。 */
function toStops(bag: Bag): RouteStopItem[] {
  return bag.stages.map((stage, index) => ({
    id: `${bag.tagNumber}-${stage.key}`,
    seq: index + 1,
    title: STAGE_LABEL[stage.key],
    description: STAGE_DETAIL[stage.key],
    status: stage.status,
    plannedTime: stage.plannedTime,
    actualTime: stage.actualTime,
  }));
}

export interface BagTrackerProps {
  bag: Bag;
  record: BaggageRecord;
}

/**
 * 1個のお預け手荷物の状態進行を表示する。
 * - RouteStops で 受託 → 受取可能 までの順序づいたステージを描画。
 * - 受取可能なら受取案内（ターンテーブル・受取所）を表示。
 * - 遅延していれば注意喚起。
 */
export function BagTracker({ bag, record }: BagTrackerProps) {
  const claimable = isClaimable(bag);
  const delayed = isDelayed(bag);

  return (
    <div className="flex flex-col gap-4">
      {claimable ? (
        <Alert variant="success">
          <IconMapPin className="size-4" aria-hidden="true" />
          <AlertTitle as="h3">受取可能になりました</AlertTitle>
          <AlertDescription>
            <MetadataList
              className="mt-1"
              variant="compact"
              items={[
                { label: "ターンテーブル", value: <span className="text-base font-bold tabular-nums">{record.carousel}番</span> },
                { label: "到着空港", value: `${record.flight.toName}（${record.flight.toCode}）` },
                { label: "受取所", value: record.claimAreaNote ?? "—" },
              ]}
            />
          </AlertDescription>
        </Alert>
      ) : null}

      {delayed && !claimable ? (
        <Alert variant="warning">
          <IconLuggage className="size-4" aria-hidden="true" />
          <AlertTitle as="h3">到着が遅れています</AlertTitle>
          <AlertDescription>
            この手荷物は後続の便で輸送されている可能性があります。受取所の到着案内表示をご確認ください。見つからない場合は手荷物事故報告（PIR）の手続きへお進みください。
          </AlertDescription>
        </Alert>
      ) : null}

      <div>
        <div className="mb-2 flex flex-wrap items-center gap-2">
          <IconRoute className="size-4 text-muted-foreground" aria-hidden="true" />
          <h3 className="text-sm font-semibold text-foreground">手荷物の状態進行</h3>
          {delayed ? (
            <Badge variant="warning">遅延あり</Badge>
          ) : claimable ? (
            <Badge variant="success">受取可能</Badge>
          ) : (
            <Badge variant="info">輸送中</Badge>
          )}
        </div>
        <RouteStops
          stops={toStops(bag)}
          statusLabels={STATUS_LABELS}
          timeLabels={{ planned: "予定", actual: "実績" }}
          aria-label={`${bag.nickname}（タグ番号 ${bag.tagNumber}）の状態進行`}
        />
      </div>
    </div>
  );
}

/**
 * 手荷物追跡（受託手荷物トラッキング）のドメインモデルとサンプルデータ。
 *
 * 旅客が自分のお預け手荷物が今どこにあるかを確認する画面のためのデータ。
 * RouteStops の RouteStopStatus 体系に合わせて手荷物の状態進行を表現する。
 */

import type { RouteStopStatus } from "@gunjo/ui";

/** 手荷物の状態進行ステージ（受託 → 受取可能までの定義された順序）。 */
export type BaggageStageKey =
  | "checkedIn" //  お預かり済（チェックインカウンター）
  | "security" //   保安検査通過
  | "loaded" //     ご搭乗便に搭載済
  | "inTransit" //  輸送中
  | "transfer" //   乗り継ぎ（積み替え）— 直行便では使わない
  | "arrived" //    到着空港に到着
  | "claimable"; // 受取可能（ターンテーブル）

/** ステージの日本語ラベル（旅客向け文言）。 */
export const STAGE_LABEL: Record<BaggageStageKey, string> = {
  checkedIn: "お預かり済",
  security: "保安検査通過",
  loaded: "搭載済",
  inTransit: "輸送中",
  transfer: "乗り継ぎ（積み替え）",
  arrived: "到着空港に到着",
  claimable: "受取可能",
};

/** ステージの補足説明。 */
export const STAGE_DETAIL: Record<BaggageStageKey, string> = {
  checkedIn: "チェックインカウンターでお預かりしました",
  security: "受託手荷物の保安検査を通過しました",
  loaded: "ご搭乗便のコンテナに搭載されました",
  inTransit: "貨物室で輸送中です",
  transfer: "乗り継ぎ便への積み替えを行っています",
  arrived: "到着空港の手荷物取扱施設に到着しました",
  claimable: "手荷物受取所でお受け取りいただけます",
};

export interface BaggageStage {
  key: BaggageStageKey;
  /** RouteStops に渡す状態。completed/current/pending/delayed/failed。 */
  status: RouteStopStatus;
  /** 予定時刻 "HH:MM"（あれば）。 */
  plannedTime?: string;
  /** 実績時刻 "HH:MM"（完了済みのステージのみ）。 */
  actualTime?: string;
}

export interface Bag {
  /** お預け手荷物タグ番号（バゲージタグ）。 */
  tagNumber: string;
  /** 旅客が識別しやすいニックネーム。 */
  nickname: string;
  /** 重量（kg）。 */
  weightKg: number;
  /** このバッグのステージ進行。 */
  stages: BaggageStage[];
}

export interface Flight {
  /** 便名（NH/JL + 数字）。 */
  flightNo: string;
  airlineLabel: string;
  /** 出発空港 IATA。 */
  fromCode: string;
  fromName: string;
  /** 到着空港 IATA。 */
  toCode: string;
  toName: string;
  /** 運航日（YYYY-MM-DD）。 */
  date: string;
  dateLabel: string;
  /** 乗り継ぎ便かどうか。 */
  hasTransfer: boolean;
}

export interface BaggageRecord {
  /** 予約参照番号（PNR）。 */
  pnr: string;
  passengerName: string;
  flight: Flight;
  /** 到着予定（HH:MM）。 */
  scheduledArrival: string;
  /** 受取所のターンテーブル番号（受取可能になったら確定）。 */
  carousel?: string;
  /** 受取所の場所案内。 */
  claimAreaNote?: string;
  /** データ最終更新時刻。 */
  lastUpdated: string;
  bags: Bag[];
}

/**
 * サンプル: NH 構成。羽田(HND) → 新千歳(CTS) の直行便、2個のお預け手荷物。
 * 1個は受取可能、もう1個は輸送中（少し遅れて流れている）という現実的なズレを表現。
 */
export const BAGGAGE_RECORD: BaggageRecord = {
  pnr: "ABC123",
  passengerName: "ヤマダ タロウ 様",
  flight: {
    flightNo: "NH 061",
    airlineLabel: "ANA / 全日本空輸",
    fromCode: "HND",
    fromName: "東京（羽田）",
    toCode: "CTS",
    toName: "新千歳",
    date: "2026-06-27",
    dateLabel: "2026年6月27日（土）",
    hasTransfer: false,
  },
  scheduledArrival: "11:45",
  carousel: "8",
  claimAreaNote: "国内線手荷物受取所（1F）・ターンテーブル 8番",
  lastUpdated: "11:52",
  bags: [
    {
      tagNumber: "NH 012345",
      nickname: "黒のスーツケース（大）",
      weightKg: 18.4,
      stages: [
        { key: "checkedIn", status: "completed", plannedTime: "09:30", actualTime: "09:28" },
        { key: "security", status: "completed", plannedTime: "09:45", actualTime: "09:41" },
        { key: "loaded", status: "completed", plannedTime: "10:10", actualTime: "10:06" },
        { key: "inTransit", status: "completed", plannedTime: "10:30", actualTime: "10:35" },
        { key: "arrived", status: "completed", plannedTime: "11:45", actualTime: "11:48" },
        { key: "claimable", status: "current", plannedTime: "11:55" },
      ],
    },
    {
      tagNumber: "NH 012346",
      nickname: "ゴルフバッグ",
      weightKg: 9.2,
      stages: [
        { key: "checkedIn", status: "completed", plannedTime: "09:32", actualTime: "09:30" },
        { key: "security", status: "completed", plannedTime: "09:47", actualTime: "09:44" },
        { key: "loaded", status: "completed", plannedTime: "10:12", actualTime: "10:09" },
        // 大型手荷物は後着便扱い。輸送がやや遅延して流れている。
        { key: "inTransit", status: "delayed", plannedTime: "10:30", actualTime: "10:58" },
        { key: "arrived", status: "pending", plannedTime: "12:10" },
        { key: "claimable", status: "pending", plannedTime: "12:20" },
      ],
    },
  ],
};

/** バッグが受取可能かどうか。 */
export function isClaimable(bag: Bag): boolean {
  return bag.stages.some((s) => s.key === "claimable" && (s.status === "current" || s.status === "completed"));
}

/** バッグが遅延しているか。 */
export function isDelayed(bag: Bag): boolean {
  return bag.stages.some((s) => s.status === "delayed");
}

/** バッグの現在ステージ（current優先、なければ最後の完了ステージ）。 */
export function currentStage(bag: Bag): BaggageStage {
  return (
    bag.stages.find((s) => s.status === "current") ??
    bag.stages.find((s) => s.status === "delayed") ??
    [...bag.stages].reverse().find((s) => s.status === "completed") ??
    bag.stages[0]
  );
}
